<?php declare(strict_types=1);use App\Support\View;$edit=$mode==='edit';$base='/admin/people/'.$person->id.'/capacity/overrides';$action=$edit?$base.'/'.$override->id:$base;?>
<div class="row justify-content-center"><div class="col-lg-8"><h1 class="h2"><?= View::escape($title) ?></h1><p><?= View::escape($person->fullName()) ?> · Standard capacity <?= View::escape($person->defaultMonthlyCapacityHours) ?> hours</p><div class="card card-body mb-3"><strong>Selected-month context</strong><span>Current effective capacity: <?= View::escape($current->capacity->effectiveHours) ?> (<?= View::escape($current->capacity->source) ?>)</span><span>Allocated: <?= View::escape($current->allocatedHours()) ?></span><span>Remaining: <?= View::escape($current->remaining($decimals)) ?></span></div><form class="card card-body" method="post" action="<?= View::escape($urls->to($action)) ?>" novalidate><input type="hidden" name="_csrf" value="<?= View::escape($csrfToken) ?>"><div class="row g-3"><div class="col-md-4"><label class="form-label" for="year">Year</label><input class="form-control<?= isset($errors['year'])?' is-invalid':'' ?>" id="year" name="year" value="<?= View::escape($values['year']??'') ?>"><?php if(isset($errors['year'])):?><div class="invalid-feedback"><?= View::escape($errors['year']) ?></div><?php endif;?></div><div class="col-md-4"><label class="form-label" for="month">Month</label><select class="form-select<?= isset($errors['month'])?' is-invalid':'' ?>" id="month" name="month"><?php for($m=1;$m<=12;$m++):?><option value="<?= $m ?>" <?= ($values['month']??'')===(string)$m?'selected':'' ?>><?= (new DateTimeImmutable(sprintf('2026-%02d-01',$m)))->format('F') ?></option><?php endfor;?></select><?php if(isset($errors['month'])):?><div class="invalid-feedback"><?= View::escape($errors['month']) ?></div><?php endif;?></div><div class="col-md-4"><label class="form-label" for="available_hours">Available hours</label><input class="form-control<?= isset($errors['available_hours'])?' is-invalid':'' ?>" id="available_hours" name="available_hours" inputmode="decimal" value="<?= View::escape($values['available_hours']??'') ?>"><?php if(isset($errors['available_hours'])):?><div class="invalid-feedback"><?= View::escape($errors['available_hours']) ?></div><?php endif;?></div><div class="col-12"><label class="form-label" for="notes">Administrative notes</label><textarea class="form-control<?= isset($errors['notes'])?' is-invalid':'' ?>" id="notes" name="notes" maxlength="2000"><?= View::escape($values['notes']??'') ?></textarea><?php if(isset($errors['notes'])):?><div class="invalid-feedback"><?= View::escape($errors['notes']) ?></div><?php endif;?><div class="form-text">Administrator-only. This value replaces standard capacity only for the selected month. Capacity below allocations is allowed and produces warnings.</div></div></div><button class="btn btn-primary mt-4 align-self-start"><?= $edit?'Save changes':'Create override' ?></button></form></div></div>
